// МОДУЛЬНЫЙ ТЕСТ (ViewModel + Mock Repository)
@Test
fun `login should update state on success`() = runTest {
    val mockRepo = mock<AuthRepository>()
    val viewModel = AuthViewModel(mockRepo)

    viewModel.login("test@email.com", "pass")

    verify(mockRepo).login("test@email.com", "pass")
    assertTrue(viewModel.state.value.isLoading)
}

// ИНТЕГРАЦИОННЫЙ ТЕСТ (Repository + Real API + DB)
@Test
fun `repository should sync user data`() = runTest {
    // Real test API with MockWebServer
    val api = createTestApi() 
    // In-memory database
    val db = createTestDb()
    val repo = UserRepository(api, db)

    repo.syncUserData("1")

    val localUser = db.userDao().getById("1")
    assertNotNull(localUser)
}
